import{_ as t,r as o,o as i,c as l,e as n,f as s,b as p,d as a}from"./app-51f2a91d.js";const c={},r=a('<h1 id="sse事件-server-sent-events" tabindex="-1"><a class="header-anchor" href="#sse事件-server-sent-events" aria-hidden="true">#</a> SSE事件 (Server-Sent Events)</h1><blockquote><p><strong>引言</strong> 在上一篇《WebSocket 协议》中，我们见识了全双工通信的威力。但你是否想过：</p><p>如果我只是想做一个<strong>股票行情看板</strong>，或者仅仅是<strong>接收 ChatGPT 吐出来的逐字回答</strong>？ 在这些场景下，<strong>客户端根本不需要向服务端高频发送消息，只需要服务端单向、源源不断地把数据“推”给客户端就够了。</strong></p><p>为了这种“单向推送”的场景去搭建一套沉重复杂的 WebSocket 架构，还要处理心跳保活、协议升级，显然是杀鸡用牛刀。</p><p>那么，有没有一种技术，既能像 WebSocket 一样实时推送，又能在底层<strong>完美复用现有的 HTTP 协议</strong>，极其轻量优雅？</p><p>答案是肯定的，它就是今天的主角 —— <strong>Server-Sent Events (SSE)</strong>。</p></blockquote><hr><h2 id="一、-sse-的诞生-化繁为简的单向奔赴" tabindex="-1"><a class="header-anchor" href="#一、-sse-的诞生-化繁为简的单向奔赴" aria-hidden="true">#</a> 一、 SSE 的诞生：化繁为简的单向奔赴</h2><p>在 WebSocket 诞生之前，如果服务端想主动给浏览器发消息，前端只能用恶心的“长轮询（Long Polling）”死等。</p><p>HTML5 标准委员会认为，长轮询太野蛮了，我们需要一个原生的、优雅的单向推送标准。于是，<strong>Server-Sent Events (SSE)</strong> 应运而生。</p><h3 id="_1-sse-与-websocket-的巅峰对决" tabindex="-1"><a class="header-anchor" href="#_1-sse-与-websocket-的巅峰对决" aria-hidden="true">#</a> 1. SSE 与 WebSocket 的巅峰对决</h3><p>很多面试官喜欢问：<strong>“既然有了 WebSocket，为什么还要用 SSE？”</strong> 其实它们的定位完全不同：</p>',8),d=n("thead",null,[n("tr",null,[n("th",{style:{"text-align":"left"}},"特性对比"),n("th",{style:{"text-align":"left"}},"WebSocket (WS)"),n("th",{style:{"text-align":"left"}},"Server-Sent Events (SSE)")])],-1),u=n("tr",null,[n("td",{style:{"text-align":"left"}},[n("strong",null,"通信方向")]),n("td",{style:{"text-align":"left"}},[n("strong",null,"全双工"),s(" (双向随时发)")]),n("td",{style:{"text-align":"left"}},[n("strong",null,"单向"),s(" (仅服务端 -> 客户端)")])],-1),v=n("tr",null,[n("td",{style:{"text-align":"left"}},[n("strong",null,"底层协议")]),n("td",{style:{"text-align":"left"}},"独立的 WebSocket 协议 (需升级)"),n("td",{style:{"text-align":"left"}},[n("strong",null,"纯正的 HTTP 协议")])],-1),k=n("tr",null,[n("td",{style:{"text-align":"left"}},[n("strong",null,"数据格式")]),n("td",{style:{"text-align":"left"}},"二进制帧 / 文本流"),n("td",{style:{"text-align":"left"}},[n("strong",null,"纯文本 (UTF-8)")])],-1),h=n("tr",null,[n("td",{style:{"text-align":"left"}},[n("strong",null,"自动重连")]),n("td",{style:{"text-align":"left"}},"❌ 需前端手写重连逻辑"),n("td",{style:{"text-align":"left"}},[s("✅ "),n("strong",null,"浏览器原生自带断线自动重连")])],-1),g=n("td",{style:{"text-align":"left"}},[n("strong",null,"复杂程度")],-1),m={style:{"text-align":"left"}},b={href:"http://Socket.io",target:"_blank",rel:"noopener noreferrer"},S=n("td",{style:{"text-align":"left"}},[s("极低 (原生 "),n("code",null,"EventSource"),s(" API)")],-1),f=a(`<p><strong>一句话总结：</strong></p><ul><li>需要双向疯狂交流（如多人联机游戏、聊天室），用 <strong>WebSocket</strong>。</li><li>只需要服务端单向广播数据（如 ChatGPT 打字机、系统通知、实时大屏），<strong>SSE 是绝对的王者</strong>。</li></ul><hr><h2 id="二、-sse-的底层原理-一个永远不会结束的-http-响应" tabindex="-1"><a class="header-anchor" href="#二、-sse-的底层原理-一个永远不会结束的-http-响应" aria-hidden="true">#</a> 二、 SSE 的底层原理：一个永远不会结束的 HTTP 响应</h2><p>很多新手觉得 SSE 很神秘，其实它的底层原理极其简单，甚至简单到让人觉得“就这？”。</p><p><strong>SSE 的本质，就是一个普通的 HTTP GET 请求，只不过服务端把响应头做了一点手脚，并且永远不挂断连接。</strong></p><h3 id="_1-核心的-http-header-魔法" tabindex="-1"><a class="header-anchor" href="#_1-核心的-http-header-魔法" aria-hidden="true">#</a> 1. 核心的 HTTP Header 魔法</h3><p>当浏览器通过 SSE 发起请求时，服务端只需要返回三个特殊的 Header：</p><div class="language-http line-numbers-mode" data-ext="http"><pre class="language-http"><code><span class="token response-status"><span class="token http-version property">HTTP/1.1</span> <span class="token status-code number">200</span> <span class="token reason-phrase string">OK</span></span>
<span class="token header"><span class="token header-name keyword">Content-Type</span><span class="token punctuation">:</span> <span class="token header-value">text/event-stream    &lt;-- 🌟 核心：告诉浏览器，我要开始发事件流了！</span></span>
<span class="token header"><span class="token header-name keyword">Cache-Control</span><span class="token punctuation">:</span> <span class="token header-value">no-cache            &lt;-- 必须的：禁止浏览器和代理缓存这些数据</span></span>
<span class="token header"><span class="token header-name keyword">Connection</span><span class="token punctuation">:</span> <span class="token header-value">keep-alive             &lt;-- 必须的：保持 TCP 连接不要断开</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当浏览器看到 <code>Content-Type: text/event-stream</code> 时，它就明白了：“哦，原来后端老哥不是要一次性给我一个完整的 JSON，而是要像挤牙膏一样，一段一段地给我发纯文本事件。”</p><h3 id="_2-独特的-挤牙膏-数据格式" tabindex="-1"><a class="header-anchor" href="#_2-独特的-挤牙膏-数据格式" aria-hidden="true">#</a> 2. 独特的“挤牙膏”数据格式</h3><p>连接建立后，服务端怎么给前端发数据呢？SSE 规定了一种极其简单的纯文本格式（必须以 <code>\\n\\n</code> 结尾代表一条消息结束）：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>data: 这是第一条消息\\n\\n

data: {&quot;user&quot;:&quot;Tom&quot;,&quot;msg&quot;:&quot;JSON也能发&quot;}\\n\\n

event: userlogin   &lt;-- 还能自定义事件名字！
data: {&quot;id&quot;: 123}\\n\\n

id: 99             &lt;-- 还能给消息编号！(用于断线续传)
data: 这是带编号的消息\\n\\n
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>服务端只要按照这个格式不断地 <code>res.write()</code> 输出字符串，前端就能源源不断地收到事件触发。</p><hr><h2 id="三、-使用场景-chatgpt-是如何利用-sse-的" tabindex="-1"><a class="header-anchor" href="#三、-使用场景-chatgpt-是如何利用-sse-的" aria-hidden="true">#</a> 三、 使用场景：ChatGPT 是如何利用 SSE 的？</h2><p>近年来，随着大语言模型（LLM）的爆发，SSE 迎来了它的高光时刻。</p><p>如果你用过 ChatGPT，你会发现它的回答是<strong>一个字一个字蹦出来的（打字机效果）</strong>。</p><ul><li><strong>如果用普通 HTTP 请求</strong>：前端必须死等 AI 把几千字的回答全部生成完毕，这可能需要几十秒，用户早就关闭网页了。</li><li><strong>为什么不用 WebSocket？</strong>：杀鸡用牛刀，而且公司原本的 Nginx 网关和 HTTP 负载均衡设施可能不支持 WebSocket 升级，改造成本极高。</li><li><strong>完美契合的 SSE</strong>：ChatGPT 采用了 SSE。前端发送提问后，AI 后端每生成一个词，就按照 <code>data: 词语\\n\\n</code> 的格式推给前端。前端瞬间渲染，用户体验极佳，且完全复用了现有的 HTTP 基建。</li></ul><p><strong>其他经典场景：</strong></p><ul><li><strong>股票/加密货币的实时 K 线图</strong></li><li><strong>服务器系统状态/日志的实时监控面板</strong></li><li><strong>扫码登录的确认状态推送</strong></li></ul><hr><h2 id="四、-前端实战-优雅至极的-eventsource-api" tabindex="-1"><a class="header-anchor" href="#四、-前端实战-优雅至极的-eventsource-api" aria-hidden="true">#</a> 四、 前端实战：优雅至极的 EventSource API</h2><p>在现代浏览器中，前端使用 SSE 简直就是一种享受。不需要安装任何第三方库，浏览器原生提供了一个极其强大的对象：<strong><code>EventSource</code></strong>。</p><h3 id="_1-建立连接与监听默认消息" tabindex="-1"><a class="header-anchor" href="#_1-建立连接与监听默认消息" aria-hidden="true">#</a> 1. 建立连接与监听默认消息</h3><p>只需三行代码，你就能搞定实时推送：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1. 发起一个普通的 GET 请求，告诉服务器我准备接收事件流了</span>
<span class="token keyword">const</span> sse <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">EventSource</span><span class="token punctuation">(</span><span class="token string">&#39;https://api.example.com/stream&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 2. 监听默认的 &#39;message&#39; 事件（当后端不指定 event 名字时触发）</span>
sse<span class="token punctuation">.</span><span class="token function-variable function">onmessage</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// event.data 就是后端发来的字符串内容</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;📩 收到服务器推送的新消息:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">.</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 如果后端发的是 JSON 字符串，记得解析</span>
    <span class="token keyword">const</span> dataObj <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span>event<span class="token punctuation">.</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
    document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;stock-price&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>innerText <span class="token operator">=</span> dataObj<span class="token punctuation">.</span>price<span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// 3. 监听连接建立成功事件</span>
sse<span class="token punctuation">.</span><span class="token function-variable function">onopen</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;✅ SSE 连接已成功建立！&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-监听自定义事件与错误处理" tabindex="-1"><a class="header-anchor" href="#_2-监听自定义事件与错误处理" aria-hidden="true">#</a> 2. 监听自定义事件与错误处理</h3><p>SSE 的强大之处在于，后端可以对消息进行分类（触发不同的事件名），而且<strong>浏览器自带极其强大的断线重连机制</strong>。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 监听后端指定的自定义事件 (例如后端写了: event: user-login\\n data: ...\\n\\n)</span>
sse<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;user-login&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;👤 有新用户登录了:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">.</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 监听错误事件（网络断开、服务器崩溃等）</span>
sse<span class="token punctuation">.</span><span class="token function-variable function">onerror</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">error</span><span class="token punctuation">(</span><span class="token string">&#39;❌ SSE 连接发生错误！&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 🌟 SSE 的超级特性：你什么都不用写，浏览器会自动在几秒后尝试重新连接服务器！</span>
    <span class="token comment">// 并且如果后端发过 id 字段，浏览器重连时会自动在请求头里带上 Last-Event-ID，</span>
    <span class="token comment">// 告诉后端：“我刚才断线前最后收到的消息ID是99，请从100开始发给我。”</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-手动关闭连接" tabindex="-1"><a class="header-anchor" href="#_3-手动关闭连接" aria-hidden="true">#</a> 3. 手动关闭连接</h3><p>因为 SSE 是一个永远不结束的 HTTP 响应，如果你离开了当前页面，一定要记得把它关掉，否则会一直占用浏览器的并发连接数。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 当组件销毁或用户退出时调用</span>
<span class="token keyword">function</span> <span class="token function">closeStream</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    sse<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;🔌 SSE 连接已手动关闭&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="五、真实场景避坑指南" tabindex="-1"><a class="header-anchor" href="#五、真实场景避坑指南" aria-hidden="true">#</a> 五、真实场景避坑指南</h2><p>当你在本地开发环境（Localhost）测试 SSE 时，一切都如丝般顺滑，ChatGPT 的打字机效果完美呈现。但是，一旦把代码部署到线上（经过了 Nginx、阿里云 WAF、公司内网网关、CDN 等多重关卡），<strong>前端页面就会一直 Loading，或者等了很久之后突然把所有字一次性全吐出来</strong>。</p><p>这就是 SSE 在企业级架构中最著名的**“网关缓冲陷阱”**。</p><p>为了让你在文章中把这个问题讲透，我为你梳理了它的<strong>底层原理（为什么会拦截）<strong>以及</strong>终极解决方案</strong>。你可以直接把这部分内容加入到你的 SSE 文章中作为“实战避坑指南”。</p><hr><h3 id="_1-核心原罪-网关的-水桶机制-proxy-buffering" tabindex="-1"><a class="header-anchor" href="#_1-核心原罪-网关的-水桶机制-proxy-buffering" aria-hidden="true">#</a> 1. 核心原罪：网关的“水桶机制” (Proxy Buffering)</h3><p>要理解为什么会被拦截，我们需要对比一下 SSE 的工作模式和传统网关的工作模式。</p><p><strong>【形象的比喻】</strong></p><ul><li><strong>SSE 服务端</strong>：像一个<strong>水龙头</strong>，一滴一滴地往下滴水（不断输出流式数据）。</li><li><strong>前端浏览器</strong>：拿着一个小杯子在水龙头底下，滴一滴水就喝一口（立刻渲染到页面上）。</li><li><strong>网关（Nginx）</strong>：如果在中间加了一个网关，它默认的办事逻辑是拿一个<strong>大水桶</strong>接水。它觉得：“一滴一滴给前端送太麻烦了，等我把水桶接满，或者等水龙头关了，我再端过去一次性给前端！”</li></ul><p><strong>【技术层面的真相】</strong> 传统的 HTTP 代理服务器（如 Nginx 默认配置）开启了 <strong>Proxy Buffering（代理缓冲）</strong>。</p><ol><li>正常情况下，网关收到后端的 HTTP 响应后，会把它缓存在自己的内存里。</li><li>等到把后端的完整响应全部接收完毕后，再统一打包发送给客户端。</li><li><strong>但是，SSE 是一个永远不结束的 HTTP 响应（长连接）！</strong></li><li>网关的“水桶”永远等不到接满的那一刻（或者要等很久才达到缓冲区上限），所以它死死把数据攥在手里，不肯发给前端。</li><li><strong>最终现象</strong>：前端发起了请求，状态一直是 <code>Pending</code>（Loading），什么数据也拿不到。</li></ol><hr><h3 id="_2-其他导致拦截的-连环杀手" tabindex="-1"><a class="header-anchor" href="#_2-其他导致拦截的-连环杀手" aria-hidden="true">#</a> 2. 其他导致拦截的“连环杀手”</h3><p>除了缓冲机制，多重网关还会带来以下三个致命阻碍：</p><h4 id="_1-http-1-0-降级问题" tabindex="-1"><a class="header-anchor" href="#_1-http-1-0-降级问题" aria-hidden="true">#</a> 1. HTTP/1.0 降级问题</h4><p>有些老旧的网关或代理（或者配置不当的 Nginx），在转发请求时，默认会把协议<strong>降级为 HTTP/1.0</strong>。</p><ul><li>HTTP/1.0 不支持 <code>Transfer-Encoding: chunked</code>（分块传输编码）。</li><li>它要求必须有 <code>Content-Length</code>（知道文件总大小）才会开始传输。</li><li>而 SSE 的大小是未知的！这会导致网关直接懵掉，强行切断连接或一直死等。</li></ul><h4 id="_2-网关超时限制-timeout" tabindex="-1"><a class="header-anchor" href="#_2-网关超时限制-timeout" aria-hidden="true">#</a> 2. 网关超时限制 (Timeout)</h4><p>多重网关为了保护自己不被耗尽资源，通常会设置严格的超时时间（比如 Nginx 默认的 <code>proxy_read_timeout</code> 是 60 秒）。</p><ul><li>如果你的 AI 生成比较慢，或者服务端 60 秒内没有吐出任何字。</li><li>网关就会认为：“后端是不是死机了？” 然后**“咔嚓”一刀强行切断 TCP 连接**。</li><li><strong>现象</strong>：前端突然报错，或者频繁触发 SSE 的断线重连。</li></ul><h4 id="_3-waf-web-应用防火墙-的安全拦截" tabindex="-1"><a class="header-anchor" href="#_3-waf-web-应用防火墙-的安全拦截" aria-hidden="true">#</a> 3. WAF（Web 应用防火墙）的安全拦截</h4><p>公司的安全网关或防毒软件，为了防止恶意代码，通常要求<strong>审查完整的 HTTP 响应体</strong>。</p><ul><li>既然要“完整审查”，它就必须等所有数据传完。</li><li>面对 SSE 这种无限流，WAF 根本无法完成审查，直接将其判定为异常流量并拦截。</li></ul><hr><h3 id="_3-终极实战-如何打通网关-让-sse-畅通无阻" tabindex="-1"><a class="header-anchor" href="#_3-终极实战-如何打通网关-让-sse-畅通无阻" aria-hidden="true">#</a> 3. 终极实战：如何打通网关，让 SSE 畅通无阻？</h3><p>在实际工作中，遇到这个问题，作为前端你不仅要知道原因，还要能指导运维/后端去修改配置。</p><h4 id="解法一-后端代码层面的-魔法-header-最推荐-✅" tabindex="-1"><a class="header-anchor" href="#解法一-后端代码层面的-魔法-header-最推荐-✅" aria-hidden="true">#</a> 解法一：后端代码层面的“魔法 Header”（最推荐 ✅）</h4><p>如果你无法修改 Nginx 配置，你可以让后端在代码里加上一个特殊的 HTTP 响应头： <strong><code>X-Accel-Buffering: no</code></strong></p><div class="language-http line-numbers-mode" data-ext="http"><pre class="language-http"><code><span class="token response-status"><span class="token http-version property">HTTP/1.1</span> <span class="token status-code number">200</span> <span class="token reason-phrase string">OK</span></span>
<span class="token header"><span class="token header-name keyword">Content-Type</span><span class="token punctuation">:</span> <span class="token header-value">text/event-stream</span></span>
<span class="token header"><span class="token header-name keyword">Cache-Control</span><span class="token punctuation">:</span> <span class="token header-value">no-cache</span></span>
<span class="token header"><span class="token header-name keyword">X-Accel-Buffering</span><span class="token punctuation">:</span> <span class="token header-value">no    &lt;-- 🌟 就是这行魔法代码！</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>原理</strong>：这是 Nginx 官方支持的专属 Header。Nginx 看到这个头，就会乖乖收起它的“大水桶”，立刻变成一根透明的水管，后端滴一滴水，它就瞬间转发给前端。这能解决 90% 的网关缓冲问题。</p><h4 id="解法二-修改-nginx-配置-运维层" tabindex="-1"><a class="header-anchor" href="#解法二-修改-nginx-配置-运维层" aria-hidden="true">#</a> 解法二：修改 Nginx 配置（运维层）</h4><p>如果你有 Nginx 的控制权，在对应的 <code>location</code> 块中加入以下配置：</p><div class="language-nginx line-numbers-mode" data-ext="nginx"><pre class="language-nginx"><code><span class="token directive"><span class="token keyword">location</span> /sse-endpoint</span> <span class="token punctuation">{</span>
    <span class="token comment"># 1. 关闭代理缓冲 (撤掉水桶)</span>
    <span class="token directive"><span class="token keyword">proxy_buffering</span> <span class="token boolean">off</span></span><span class="token punctuation">;</span>
    
    <span class="token comment"># 2. 强制使用 HTTP/1.1，防止被降级</span>
    <span class="token directive"><span class="token keyword">proxy_http_version</span> 1.1</span><span class="token punctuation">;</span>
    
    <span class="token comment"># 3. 清除 Connection 头，防止代理自动加上 close 导致连接断开</span>
    <span class="token directive"><span class="token keyword">proxy_set_header</span> Connection <span class="token string">&#39;&#39;</span></span><span class="token punctuation">;</span>
    
    <span class="token comment"># 4. 把超时时间拉长 (比如设为 1 小时)，防止网关主动断开</span>
    <span class="token directive"><span class="token keyword">proxy_read_timeout</span> <span class="token number">3600s</span></span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="解法三-应对超时断开的-心跳保活-heartbeat" tabindex="-1"><a class="header-anchor" href="#解法三-应对超时断开的-心跳保活-heartbeat" aria-hidden="true">#</a> 解法三：应对超时断开的“心跳保活” (Heartbeat)</h4><p>为了防止被企业防火墙或网关的超时机制（Timeout）切断，<strong>后端必须每隔一段时间（比如 15 秒）向前端发一条毫无意义的空注释或空白事件。</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># 这是一条注释，前端的 EventSource 会自动忽略它
: ping\\n\\n

data: 真正的数据\\n\\n
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>原理</strong>：网关只要看到网络管道里一直有数据在流动，就不会触发闲置超时（Idle Timeout）的断开机制。</p><hr><blockquote><p><strong>结语：</strong></p><p>从最古老简陋的 HTTP/0.9，到为了性能拼命挤海绵的 HTTP 缓存控制； 从被动防御跨域（CORS）和黑客攻击的各种 Header 盾牌，再到突破单向请求枷锁的 WebSocket 与极其轻巧的 SSE。</p><p>在这六篇文章中，我们剥开了前端那些光鲜亮丽的 UI 框架外衣，深入到了互联网数据传输的骨髓里。</p><p>HTTP 协议从来不是什么高深莫测的黑魔法，它只是一群先驱者为了让信息流转得更安全、更快速而不断修补的一套“规矩”。 当你下次再在控制台看到 <code>304 Not Modified</code>，或者在 Network 面板里看到 <code>text/event-stream</code> 时，希望你能会心一笑，因为你已经洞悉了它背后的所有秘密。</p></blockquote><hr>`,74);function x(_,T){const e=o("ExternalLinkIcon");return i(),l("div",null,[r,n("table",null,[d,n("tbody",null,[u,v,k,h,n("tr",null,[g,n("td",m,[s("高 (需引入 "),n("a",b,[s("Socket.io"),p(e)]),s(" 等庞大库)")]),S])])]),f])}const E=t(c,[["render",x],["__file","06.html.vue"]]);export{E as default};
